import{_ as a,o,c as r,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Herramientas de Moderación","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/adicional/herramientas.md","filePath":"maxstaff/adicional/herramientas.md"}'),i={name:"maxstaff/adicional/herramientas.md"};function n(s,e,l,d,c,u){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="herramientas-de-moderacion" tabindex="-1">Herramientas de Moderación <a class="header-anchor" href="#herramientas-de-moderacion" aria-label="Permalink to &quot;Herramientas de Moderación&quot;">​</a></h1><blockquote><p>MaxStaff incluye un conjunto de utilidades diseñadas para facilitar el control del servidor, revertir daños causados por hackers y monitorear a los jugadores de forma avanzada.</p></blockquote><h2 id="_1-restauracion-de-inventarios-revive" tabindex="-1">1. Restauración de Inventarios (Revive) <a class="header-anchor" href="#_1-restauracion-de-inventarios-revive" aria-label="Permalink to &quot;1. Restauración de Inventarios (Revive)&quot;">​</a></h2><blockquote><p>El sistema guarda automáticamente una captura (snapshot) del inventario y la armadura de un jugador cada vez que muere. Es la herramienta perfecta para devolverle sus cosas a un usuario si fue asesinado por un tramposo o un error del servidor.</p></blockquote><ul><li><strong>Comando:</strong> <code>/revive &lt;jugador&gt;</code></li><li><strong>Uso:</strong> Al ejecutar el comando, se abrirá un menú interactivo mostrando el historial de muertes recientes del jugador. Con un solo clic, el inventario previo a esa muerte será restaurado por completo.</li></ul><h2 id="_2-deteccion-de-clientes-client-tracker" tabindex="-1">2. Detección de Clientes (Client Tracker) <a class="header-anchor" href="#_2-deteccion-de-clientes-client-tracker" aria-label="Permalink to &quot;2. Detección de Clientes (Client Tracker)&quot;">​</a></h2><blockquote><p>MaxStaff detecta automáticamente la marca del cliente que están usando los jugadores para conectarse al servidor (Vanilla, Lunar Client, Forge, Fabric, etc.).</p></blockquote><ul><li><strong>¿Cómo funciona?</strong> El plugin lee los canales de datos internos al momento de la conexión.</li><li><strong>Alertas Staff:</strong> Los miembros del equipo que tengan el permiso <code>maxstaff.client.notify</code> recibirán un mensaje silencioso en el chat indicando qué cliente está usando cada jugador al entrar, ayudando a detectar posibles clientes modificados.</li></ul><h2 id="_3-control-de-chat-global" tabindex="-1">3. Control de Chat Global <a class="header-anchor" href="#_3-control-de-chat-global" aria-label="Permalink to &quot;3. Control de Chat Global&quot;">​</a></h2><blockquote><p>Utilidades de respuesta rápida para moderar la comunicación pública en caso de raideos, spam masivo o toxicidad extrema.</p></blockquote><ul><li><strong>Limpiar Chat:</strong> Usa <code>/chat clear</code> para borrar todo el historial del chat visible al instante. Esto elimina mensajes inapropiados o links maliciosos de la pantalla de todos los jugadores.</li><li><strong>Bloquear Chat:</strong> Usa <code>/chat mute</code> para silenciar el servidor por completo. Mientras esté activo, solo los jugadores con el permiso de administrador podrán hablar. Vuelve a ejecutarlo para desbloquearlo.</li></ul><h2 id="_4-visor-de-inventarios-invsee" tabindex="-1">4. Visor de Inventarios (InvSee) <a class="header-anchor" href="#_4-visor-de-inventarios-invsee" aria-label="Permalink to &quot;4. Visor de Inventarios (InvSee)&quot;">​</a></h2><blockquote><p>Revisa lo que los jugadores llevan encima sin necesidad de estar cerca de ellos o en modo staff.</p></blockquote><ul><li><strong>Comando:</strong> <code>/invsee &lt;jugador&gt;</code></li><li><strong>Uso:</strong> Abre el inventario del jugador en tiempo real. Permite a los administradores confiscar objetos ilegales directamente desde la interfaz o revisar la armadura que llevan puesta.</li></ul>',14)])])}const h=a(i,[["render",n]]);export{p as __pageData,h as default};
